/**
 * Generated by `createservice user.AuthenticateOrRegisterUserWithConfirmTokenService --type mutations`
 */

const get = require('lodash/get')
const isNil = require('lodash/isNil')

const { GQLError, GQLErrorCode: { BAD_USER_INPUT } } = require('@open-condo/keystone/errors')
const { checkDvAndSender } = require('@open-condo/keystone/plugins/dvAndSender')
const { GQLCustomSchema, getSchemaCtx, getById, getByCondition } = require('@open-condo/keystone/schema')

const { NOT_FOUND, COMMON_ERRORS } = require('@condo/domains/common/constants/errors')
const { normalizeEmail } = require('@condo/domains/common/utils/mail')
const { normalizePhone } = require('@condo/domains/common/utils/phone')
const access = require('@condo/domains/user/access/AuthenticateOrRegisterUserWithConfirmTokenService')
const { STAFF, RESIDENT } = require('@condo/domains/user/constants/common')
const { GQL_ERRORS: USER_ERRORS } = require('@condo/domains/user/constants/errors')
const { ConfirmPhoneAction, User } = require('@condo/domains/user/utils/serverSchema')
const { checkDailyRequestLimitCountersByIp } = require('@condo/domains/user/utils/serverSchema/requestLimitHelpers')


const REQUIRED_USER_FIELDS_BY_TYPE = {
    [RESIDENT]: ['phone'],
    [STAFF]: ['phone', 'name', 'password'],
}
const SUPPORTED_USER_TYPES = [RESIDENT, STAFF]

/**
 * List of possible errors, that this custom schema can throw
 * They will be rendered in documentation section in GraphiQL for this custom schema
 */
const ERRORS = {
    REQUIRED_USER_DATA_IS_MISSING: {
        mutation: 'authenticateOrRegisterUserWithConfirmToken',
        variable: ['data', 'userData'],
        code: BAD_USER_INPUT,
        type: 'REQUIRED_USER_DATA_IS_MISSING',
        message: 'Some required user data was missing',
        messageForUser: 'api.user.authenticateOrRegisterUserWithConfirmToken.REQUIRED_USER_DATA_IS_MISSING',
    },
    NOT_SUPPORTED_USER_TYPE: {
        mutation: 'authenticateOrRegisterUserWithConfirmToken',
        variable: ['data', 'userType'],
        code: BAD_USER_INPUT,
        type: 'NOT_SUPPORTED_USER_TYPE',
        message: `Only the following user types are supported: ${SUPPORTED_USER_TYPES.join(', ')}`,
    },
    DIFFERENT_PHONE_NUMBERS: {
        mutation: 'authenticateOrRegisterUserWithConfirmToken',
        variable: ['data', 'userData', 'phone'],
        code: BAD_USER_INPUT,
        type: 'DIFFERENT_PHONE_NUMBERS',
        message: 'The verified phone number and the phone number from the payload cannot be different',
    },
    INVALID_PHONE_NUMBER: {
        mutation: 'authenticateOrRegisterUserWithConfirmToken',
        code: BAD_USER_INPUT,
        type: 'INVALID_PHONE_NUMBER',
        message: 'Invalid phone number',
        messageForUser: 'api.user.authenticateOrRegisterUserWithConfirmToken.INVALID_PHONE_NUMBER',
    },
    USER_NOT_FOUND: {
        mutation: 'authenticateOrRegisterUserWithConfirmToken',
        code: NOT_FOUND,
        type: 'USER_NOT_FOUND',
        message: 'User not found',
        messageForUser: 'api.user.authenticateOrRegisterUserWithConfirmToken.USER_NOT_FOUND',
    },
    TOKEN_NOT_FOUND: {
        mutation: 'authenticateOrRegisterUserWithConfirmToken',
        variable: ['data', 'token'],
        code: NOT_FOUND,
        type: 'TOKEN_NOT_FOUND',
        message: 'Token not found',
    },
    DV_VERSION_MISMATCH: {
        ...COMMON_ERRORS.DV_VERSION_MISMATCH,
        mutation: 'authenticateOrRegisterUserWithConfirmToken',
    },
    WRONG_SENDER_FORMAT: {
        ...COMMON_ERRORS.WRONG_SENDER_FORMAT,
        mutation: 'authenticateOrRegisterUserWithConfirmToken',
    },
    DAILY_REQUEST_LIMIT_FOR_IP_REACHED: {
        ...USER_ERRORS.DAILY_REQUEST_LIMIT_FOR_IP_REACHED,
    },
}

const getUserPayload = (user, userData) => {
    const payload = {}
    for (const [key, value] of Object.entries(userData))  {
        if (!value) continue
        if (get(user, key)) continue
        payload[key] = value
    }
    return payload
}

/**
 * Checks that all required fields are present in a user data.
 * @param {string[]} requiredFields
 * @param {*} userData
 * @return {{missingFields: string[], missingRequiredFields: boolean}}
 */
const checkRequiredUserFields = (requiredFields, userData) => {
    if (!Array.isArray(requiredFields)) throw new Error('"requiredFields" should be an array')

    const missingFields = []
    for (const field of requiredFields) {
        const value = get(userData, field, null)
        if (isNil(value)) missingFields.push(field)
        if (typeof value === 'string' && value.length < 1) missingFields.push(field)
    }
    return { missingRequiredFields: missingFields.length > 0, missingFields }
}

const AuthenticateOrRegisterUserWithConfirmTokenService = new GQLCustomSchema('AuthenticateOrRegisterUserWithConfirmTokenService', {
    types: [
        {
            access: true,
            type: 'input AuthenticateOrRegisterUserWithConfirmTokenUserDataInput { phone: String, name: String, email: String, password: String, meta: JSON }',
        },
        {
            access: true,
            type: 'input AuthenticateOrRegisterUserWithConfirmTokenInput { dv: Int!, sender: SenderFieldInput!, confirmToken: ID!, userType: UserTypeType!, userData: AuthenticateOrRegisterUserWithConfirmTokenUserDataInput }',
        },
        {
            access: true,
            type: 'type AuthenticateOrRegisterUserWithConfirmTokenOutput { item: User, token: ID! }',
        },
    ],

    mutations: [
        {
            access: access.authenticateOrRegisterUserWithConfirmToken,
            schema: 'authenticateOrRegisterUserWithConfirmToken(data: AuthenticateOrRegisterUserWithConfirmTokenInput!): AuthenticateOrRegisterUserWithConfirmTokenOutput',
            doc: {
                summary: 'This mutation authorizes the user by token, after confirming the phone number.\n\n' +
                    'If the user is not registered, then he will be created with the data that is passed in the payload (user data).\n\n' +
                    'If the existing user is missing some fields, then these fields will be taken from the payload (user data) and updated.\n\n' +
                    'This mutation is not available for service users!',
                errors: ERRORS,
            },
            resolver: async (parent, args, context) => {
                const { data } = args
                const { confirmToken, userType, userData, dv, sender } = data

                checkDvAndSender(data, ERRORS.DV_VERSION_MISMATCH, ERRORS.WRONG_SENDER_FORMAT, context)

                if (!SUPPORTED_USER_TYPES.includes(userType)) throw new GQLError(ERRORS.NOT_SUPPORTED_USER_TYPE, context)

                if (!confirmToken) throw new GQLError(ERRORS.TOKEN_NOT_FOUND, context)

                await checkDailyRequestLimitCountersByIp(context, 'authenticateOrRegisterUserWithConfirmToken', context.req.ip)

                const action = await ConfirmPhoneAction.getOne(context,
                    {
                        token: confirmToken,
                        expiresAt_gte: new Date().toISOString(),
                        completedAt: null,
                        isPhoneVerified: true,
                        deletedAt: null,
                    }
                )
                if (!action) throw new GQLError(ERRORS.TOKEN_NOT_FOUND, context)

                const dvAndSender = { dv, sender }
                const userInfo = {
                    ...userData,
                    type: userType,
                    name: String(get(userData, 'name', '')).trim() || null,
                    email: normalizeEmail(get(userData, 'email')) || null,
                    isEmailVerified: false,
                    phone: normalizePhone(get(userData, 'phone')) || null,
                    isPhoneVerified: false,
                }

                if (!!userInfo.phone && userInfo.phone !== action.phone) throw new GQLError(ERRORS.DIFFERENT_PHONE_NUMBERS, context)
                if (!action.phone) throw new GQLError(ERRORS.INVALID_PHONE_NUMBER, context)

                userInfo.phone = action.phone
                userInfo.isPhoneVerified = action.isPhoneVerified

                let user = await getByCondition('User', {
                    type: userInfo.type,
                    phone: userInfo.phone,
                })

                if (user && user.deletedAt) throw new GQLError(ERRORS.USER_NOT_FOUND, context)

                const userPayload = getUserPayload(user, userInfo)

                if (!user) {
                    const { missingRequiredFields, missingFields } = checkRequiredUserFields(REQUIRED_USER_FIELDS_BY_TYPE[userType], userPayload)
                    if (missingRequiredFields) {
                        throw new GQLError({
                            ...ERRORS.REQUIRED_USER_DATA_IS_MISSING,
                            variable: ['data', 'userData', missingFields[0]],
                            message: `Some required user data was missing: ${missingFields.join(', ')}`,
                        }, context)
                    }

                    user = await User.create(context, { ...userPayload, ...dvAndSender })
                } else if (Object.keys(userPayload).length > 0) {
                    user = await User.update(context, user.id, { ...userPayload, ...dvAndSender })
                }

                await ConfirmPhoneAction.update(context, action.id, { dv: 1, sender, completedAt: new Date().toISOString() })
                const { keystone } = getSchemaCtx('User')
                const sessionToken = await context.startAuthedSession({ item: user, list: keystone.lists['User'] })

                return {
                    item: await getById('User', user.id),
                    token: sessionToken,
                }
            },
        },
    ],
    
})

module.exports = {
    AuthenticateOrRegisterUserWithConfirmTokenService,
    ERRORS,
}
